 60→fn slash_command_name(text: &str) -> Option<&str> {
 61→    let rest = text.trim_start().strip_prefix('/')?;
 62→    let cmd = rest.split_whitespace().next().unwrap_or("");
 63→    if cmd.is_empty() {
 64→        None
 65→    } else {
 66→        Some(cmd)
 67→    }
 68→}
