1686→                    Err(e) => Err(ChannelError::external("abort", e)),
1687→                }
1688→            },
1689→            "peek" => {
1690→                let params = serde_json::json!({ "sessionKey": session_key });
1691→                match chat.peek(params).await {
1692→                    Ok(res) => {
1693→                        let active = res.get("active").and_then(|v| v.as_bool()).unwrap_or(false);
1694→                        if !active {
1695→                            return Ok("Idle — nothing running.".to_string());
1696→                        }
1697→                        let mut lines = Vec::new();
1698→                        if let Some(text) = res.get("thinkingText").and_then(|v| v.as_str()) {
1699→                            lines.push(format!("Thinking: {text}"));
1700→                        }
1701→                        if let Some(tools) = res.get("toolCalls").and_then(|v| v.as_array()) {
1702→                            for tc in tools {
1703→                                let name = tc.get("name").and_then(|v| v.as_str()).unwrap_or("?");
1704→                                lines.push(format!("  Running: {name}"));
1705→                            }
1706→                        }
1707→                        if lines.is_empty() {
1708→                            lines.push("Active (thinking…)".to_string());
1709→                        }
1710→                        Ok(lines.join("\n"))
1711→                    },
1712→                    Err(e) => Err(ChannelError::external("peek", e)),
1713→                }
1714→            },
1715→            _ => Err(ChannelError::invalid_input(format!(
1716→                "unknown command: /{cmd}"
1717→            ))),
1718→        }

  1→//! Native Discord slash command registration and handling.
  2→//!
  3→//! Registers global application commands (/new, /model, /help, etc.) when the
  4→//! bot connects, and dispatches interactions through the same `dispatch_command`
  5→//! path used by text-based `/` commands.
  6→
  7→use {
  8→    serenity::all::{
  9→        Command, CommandInteraction, ComponentInteraction, Context, CreateCommand,
 10→        CreateInteractionResponse, CreateInteractionResponseFollowup, EditInteractionResponse,
 11→        Interaction,
 12→    },
 13→    tracing::{debug, info, warn},
 14→};
 15→
 16→use crate::state::AccountStateMap;
 17→
 18→/// Build the set of global slash commands to register.
 19→pub fn build_commands() -> Vec<CreateCommand> {
 20→    vec![
 21→        CreateCommand::new("new").description("Start a new chat session"),
 22→        CreateCommand::new("clear").description("Clear the current session history"),
 23→        CreateCommand::new("compact").description("Summarize the current session"),
 24→        CreateCommand::new("context").description("Show session info (model, tokens, plugins)"),
 25→        CreateCommand::new("model").description("List or switch the AI model"),
 26→        CreateCommand::new("sessions").description("List or switch chat sessions"),
 27→        CreateCommand::new("agent").description("List or switch agents"),
 28→        CreateCommand::new("help").description("Show available commands"),
 29→    ]
 30→}
 31→
 32→/// Register global slash commands for the bot.
 33→pub async fn register_global_commands(ctx: &Context, account_id: &str) {
 34→    match Command::set_global_commands(&ctx, build_commands()).await {
 35→        Ok(commands) => {
 36→            let names: Vec<&str> = commands.iter().map(|c| c.name.as_str()).collect();
 37→            info!(
 38→                account_id,
 39→                commands = ?names,
 40→                "Registered {} Discord slash commands",
 41→                commands.len()
 42→            );
 43→        },
 44→        Err(e) => {
 45→            warn!(account_id, "Failed to register Discord slash commands: {e}");
 46→        },
 47→    }
 48→}
 49→
 50→/// Handle an incoming interaction (slash command, button click, etc.).
 51→pub async fn handle_interaction(
 52→    ctx: &Context,
 53→    interaction: &Interaction,
 54→    account_id: &str,
 55→    accounts: &AccountStateMap,
 56→) {
 57→    match interaction {
 58→        Interaction::Command(command) => {
 59→            handle_slash_command(ctx, command, account_id, accounts).await;
 60→        },
 61→        Interaction::Component(component) => {
 62→            handle_component_interaction(ctx, component, account_id, accounts).await;
 63→        },
 64→        _ => {},
 65→    }
 66→}
 67→
 68→/// Handle a slash command interaction.
 69→async fn handle_slash_command(
 70→    ctx: &Context,
 71→    command: &CommandInteraction,
 72→    account_id: &str,
 73→    accounts: &AccountStateMap,
 74→) {
 75→    debug!(
 76→        account_id,
 77→        command = %command.data.name,
 78→        user = %command.user.name,
 79→        "Discord slash command received"
 80→    );
 81→
 82→    if let Err(e) = command.defer_ephemeral(ctx).await {
 83→        warn!(
 84→            command = %command.data.name,
 85→            "Failed to acknowledge slash command: {e}"
 86→        );
 87→        return;
 88→    }
 89→
 90→    let event_sink = {
 91→        let accts = accounts.read().unwrap_or_else(|e| e.into_inner());
 92→        accts.get(account_id).and_then(|s| s.event_sink.clone())
 93→    };
 94→
 95→    let Some(sink) = event_sink else {
 96→        respond_ephemeral(ctx, command, "Bot is not ready yet.").await;
 97→        return;
 98→    };
 99→
100→    let reply_to = moltis_channels::plugin::ChannelReplyTarget {
101→        channel_type: moltis_channels::ChannelType::Discord,
102→        account_id: account_id.to_string(),
103→        chat_id: command.channel_id.to_string(),
104→        message_id: None,
105→        thread_id: None,
106→    };
107→
108→    let response_text = match sink.dispatch_command(&command.data.name, reply_to).await {
109→        Ok(response) => response,
110→        Err(e) => format!("Command failed: {e}"),
111→    };
112→
113→    respond_ephemeral(ctx, command, &response_text).await;
114→}
115→
116→/// Handle a component (button click) interaction.
117→async fn handle_component_interaction(
118→    ctx: &Context,
119→    component: &ComponentInteraction,
120→    account_id: &str,
121→    accounts: &AccountStateMap,
122→) {
123→    let callback_data = &component.data.custom_id;
124→
125→    debug!(
126→        account_id,
127→        callback_data,
128→        user = %component.user.name,
129→        "Discord component interaction received"
130→    );
131→
132→    // Acknowledge the interaction immediately so Discord doesn't show a failure.
133→    if let Err(e) = component
134→        .create_response(ctx, CreateInteractionResponse::Acknowledge)
135→        .await
136→    {
137→        warn!(
138→            account_id,
139→            callback_data, "Failed to acknowledge component interaction: {e}"
140→        );
141→        return;
142→    }
143→
144→    let event_sink = {
145→        let accts = accounts.read().unwrap_or_else(|e| e.into_inner());
146→        accts.get(account_id).and_then(|s| s.event_sink.clone())
147→    };
148→
149→    let Some(sink) = event_sink else {
150→        return;
151→    };
152→
153→    let reply_to = moltis_channels::plugin::ChannelReplyTarget {
154→        channel_type: moltis_channels::ChannelType::Discord,
155→        account_id: account_id.to_string(),
156→        chat_id: component.channel_id.to_string(),
157→        message_id: None,
158→        thread_id: None,
159→    };
160→
161→    match sink.dispatch_interaction(callback_data, reply_to).await {
162→        Ok(_response) => {
163→            // Response already sent by the gateway.
164→        },
165→        Err(e) => {
166→            debug!(
167→                account_id,
168→                callback_data, "interaction dispatch failed: {e}"
169→            );
170→        },
171→    }
172→}
173→
174→/// Send an ephemeral response to a slash command (only visible to the invoker).
175→async fn respond_ephemeral(ctx: &Context, command: &CommandInteraction, text: &str) {
176→    if let Err(e) = command
177→        .edit_response(&ctx, EditInteractionResponse::new().content(text))
178→        .await
179→    {
180→        warn!(
181→            command = %command.data.name,
182→            "Failed to edit deferred slash response: {e}"
183→        );
184→        if let Err(followup_err) = command
185→            .create_followup(
186→                &ctx,
187→                CreateInteractionResponseFollowup::new()
188→                    .content(text)
189→                    .ephemeral(true),
190→            )
191→            .await
192→        {
193→            warn!(
194→                command = %command.data.name,
195→                "Failed to send slash follow-up response: {followup_err}"
196→            );
197→        }
198→    }
199→}
