}

fn infer_chat_type(
    direct_flag: bool,
    active_members_count: u64,
    joined_members_count: u64,
) -> ChatType {
    if direct_flag || active_members_count == 2 || joined_members_count == 2 {
        ChatType::Dm
    } else {
        ChatType::Group
    }
}

