    #[test]
    fn utd_notice_window_throttles_repeated_notices() {
        let mut notices = HashMap::new();
        let now = Instant::now();

        assert!(update_utd_notice_window(
            &mut notices,
            "!room:example.org",
            now
        ));
        assert!(!update_utd_notice_window(
            &mut notices,
            "!room:example.org",
            now + Duration::from_secs(60),
        ));
        assert!(update_utd_notice_window(
            &mut notices,
            "!room:example.org",
            now + Duration::from_secs(301),
        ));
    }

    #[test]
